-- noinspection SqlNoDataSourceInspectionForFile

BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS categorie (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    parent_id INTEGER NULL,
    name TEXT NOT NULL,
    FOREIGN KEY (parent_id) REFERENCES categorie(id)
);
CREATE TABLE IF NOT EXISTS historique_achats (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    date_achat DATETIME,
    details_json TEXT
);
CREATE TABLE IF NOT EXISTS ingredient (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    description TEXT,
    category_id INTEGER,
    insecable INTEGER DEFAULT 0,
    img_src TEXT NULL,
    FOREIGN KEY (category_id) REFERENCES categorie(id)
);
CREATE TABLE IF NOT EXISTS recette (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    description TEXT,
    nombre_personne INTEGER NOT NULL CHECK(nombre_personne >= 1),
    temps_realisation INTEGER,
    difficulte REAL CHECK(difficulte >= 0.0 AND difficulte <= 1.0)
, theme VARCHAR(50) DEFAULT 'theme-plat');
CREATE TABLE IF NOT EXISTS recette_etape (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    recette_id INTEGER NOT NULL,
    priorite INTEGER DEFAULT 1, -- Pour l'ordre (1, 2, 3...)
    type_texte TEXT CHECK( type_texte IN ('étape', 'astuce') ) DEFAULT 'étape',
    contenu TEXT NOT NULL,
    FOREIGN KEY (recette_id) REFERENCES recette(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS recette_ingredients (
    id_recette INTEGER,
    id_ingredient INTEGER,
    id_unite INTEGER,
    quantite REAL,
    info_facultative TEXT,
    PRIMARY KEY (id_recette, id_ingredient),
    FOREIGN KEY (id_recette) REFERENCES recette(id),
    FOREIGN KEY (id_ingredient) REFERENCES ingredient(id),
    FOREIGN KEY (id_unite) REFERENCES "unite"(id)
);
CREATE TABLE IF NOT EXISTS "unite" (
	"id"	INTEGER,
	"name"	TEXT NOT NULL,
	"unit_name"	TEXT NOT NULL,
	"negligeable"	INTEGER DEFAULT 0,
	"insecable"	INTEGER DEFAULT 0,
	"prefixe"	TEXT DEFAULT '',
	"suffixe"	TEXT DEFAULT '',
	"pour1kg"	REAL NOT NULL,
	"form_step"	REAL NOT NULL DEFAULT 0,
	"form_init_value"	REAL NOT NULL DEFAULT 0,
	PRIMARY KEY("id" AUTOINCREMENT)
);
COMMIT;
