INSERT INTO "recette_etape" ("id","recette_id","priorite","type_texte","contenu") VALUES (54,3,1,'étape','<h1>step 1</h1>'),
 (55,3,2,'étape','<h1>step 2</h1>'),
 (323,16,1,'astuce','<h3>Faire revenir le <strong style="color: rgb(230, 0, 0);">mou</strong>.</h3><p><img src="uploads/img_69ebc523b03a3.jpg"></p><p><strong>Mâchez.</strong></p><p>Vomissez !</p>'),
 (324,16,2,'étape','<p><span style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">Bell peppers onions bok choy beets paprika daikon radish sauerkraut carrots cucumber asparagus green onion mushrooms lobster. Butternut squash shrimp paprika, rutabaga cauliflower seaweed sauerkraut swiss chard asparagus </span><span style="background-color: rgb(178, 107, 0); color: rgb(255, 255, 0);">tomatoes broccoli kohlrabi kale potatoes</span><span style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">. </span><strong style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">Crookneck </strong><span style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">squash radish watercress carrots eggplant. Onions mushrooms rutabaga endive lettuce kohlrabi. Radish beets mushrooms paprika spaghetti squash carrots celery zucchini sweet potato cucumber spices eggplant. </span><strong style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">Fine dining watercress garlic</strong><span style="background-color: rgb(255, 255, 255); color: rgb(38, 25, 25);">, mushrooms broccoli dandelion greens radish jicama apples shrimp sweet potatoes onions tomatillo kohlrabi rutabaga. Broccoli parsnips okra sauerkraut green onion, rutabaga lobster.</span></p>'),
 (325,16,3,'étape','<p><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">on acquiert de droits aux respects de ses voisins. Les jardins de M. de Rênal, remplis de murs, sont encore admirés parce qu’il a acheté, au poids de l’or, certains petits morceaux de terrain qu’ils occupent. Par exemple, cette scie à bois, dont la position singulière sur la rive du Doubs vous a frappé en entrant à Verrières, et où vous avez remarqué le nom de Sorel, écrit en caractères gigantesques sur une planche qui domine le toit, elle occupait, il y a six ans, l’espace sur lequel on élève en ce moment le mur de la quatrième terrasse des jardins de M. de Rênal.</span></p>'),
 (326,16,4,'astuce','<p>Faites caca par terre, et <strong>admirez</strong> !</p>'),
 (327,16,5,'étape','<p><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">La réponse de Sorel ne fut d’abord que la longue récitation de toutes les formules de respect qu’il savait par cœur. Pendant qu’il répétait ces vaines paroles, avec un sourire gauche qui augmentait l’air de fausseté, et presque de friponnerie, naturel à sa physionomie, l’esprit actif du vieux paysan cherchait à découvrir quelle raison pouvait porter un homme aussi considérable à prendre chez lui son vaurien de fils. Il était fort mécontent de Julien, et c’était pour lui que M. de Rênal lui offrait le gage inespéré de 300 francs par an, avec la nourriture et même l’habillement. Cette dernière prétention, que le père Sorel avait eu le génie de mettre en avant subitement, avait été accordée de même par M. de Rênal.</span></p>'),
 (328,16,6,'étape','<p><span style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);">e friponnerie, naturel à sa physionomie, l’esprit actif du vieux paysan cherchait à découvrir quelle raison pouvait porter un homme aussi considérable à prendre chez lui son vaurien de fils. Il était fort mécontent de Julien, et c’était pour lui que M. de Rênal lui offrait le gage inespéré de 300 francs par an, avec la nourriture et même l’habillement. Cette dernière prétention, que le père Sorel avait eu le génie de mett</span></p>'),
 (329,16,7,'étape','<p><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);"> actif du vieux paysan cherchait à découvrir quelle raison pouvait porter un homme aussi considérable à prendre chez lui son vaurien de fils. Il était fort mécontent de Julien, et c’était pour lui que M. de Rênal lui offrait le gage inespéré de 300 francs par an, avec la nourriture et même l’habillement. Cette dernière prétention, que le père Sorel avait eu le génie de mett</span></p>'),
 (330,16,8,'étape','<p><span style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);">de 300 francs par an, avec la </span></p>'),
 (331,16,9,'étape','<p><span style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);"> de Rênal, remplis de murs, sont encore admirés parce qu’il a acheté, au poids de l’or, certains petits morceaux de terrain qu’ils occupent. Par exemple, cette scie à bois, dont la position singulière sur la rive du Doubs vous a frappé en entrant à Verrières, et où vous avez remarqué le nom de Sorel, écrit en caractères gigantesques sur une planche qui d</span></p>'),
 (332,16,10,'étape','<p><strong style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);">al, mais un affreux supplice venait de cesser. Pour que Mme Derville ne s’aperçût de rien, il se crut obligé de parler ; sa voix alors était éclatante et forte.</strong><strong style="color: rgb(33, 37, 41); background-color: rgb(230, 0, 0);"> Celle de Mme de Rênal</strong><strong style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);">, au contraire, trahissait <u>tant d’émotion, que son amie la crut malade et lui proposa de r</u>entrer. Julien sentit le danger : si Mme de Rênal rentre au salon, je vais retomber dans la position affreuse où j’ai p</strong></p>'),
 (333,16,11,'étape','<h1><strong style="color: rgb(33, 37, 41); background-color: rgb(255, 255, 255);">al, mais un affreux supplice<em><u> venait de cesd crut malade et lui proposa de rentrer. Julien sentit </u></em>le danger : si Mme de Rênal rentre au salon, je vais retomber dans la position affreuse où j’ai p</strong></h1>'),
 (334,16,12,'étape','<h1 class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Ma femme a réellement beaucoup de tête ! </span></h1><p class="ql-align-justify"><img src="data:image/jpeg;base64,"></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">se disait, le lendemain à six heures du matin, le maire de Verrières, en descendant à la scie du père Sorel. Quoi que je lui aie dit, pour conserver la supériorité qui m’appartient, je n’avais pas songé que si je ne prends pas ce petit abbé Sorel, qui, dit-on, sait le latin comme un ange, le directeur du dépôt, cette âme sans repos, pourrait bien avoir la même idée que moi et me l’enlever. Avec quel ton de suffisance il parlerait du précepteur de ses enfants !... Ce précepteur, une fois à moi, portera-t-il la soutane ?</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">La réponse de Sorel ne fut d’abord que la longue récitation de toutes les formules de respect qu’il savait par cœur. Pendant qu’il répétait ces vaines paroles, avec un sourire gauche qui augmentait l’air de fausseté, et presque de friponnerie, naturel à sa physionomie, l’esprit actif du vieux paysan cherchait à découvrir quelle raison pouvait porter un homme aussi considérable à prendre chez lui son vaurien de fils. Il était fort mécontent de Julien, et c’était pour lui que M. de Rênal lui offrait le gage inespéré de 300 francs par an, avec la nourriture et même l’habillement. Cette dernière prétention, que le père Sorel avait eu le génie de mettre en avant subitement, avait été accordée de même par M. de Rênal.</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Cette demande frappa le maire. Puisque Sorel n’est pas ravi et comblé de ma proposition, comme naturellement il devrait l’être, il est clair, se dit-il, qu’on lui a fait des offres d’un autre côté ; et de qui peuvent-elles venir, si ce n’est du Valenod ? Ce fut en vain que M. de Rênal pressa Sorel de conclure sur-le-champ : l’astuce du vieux paysan s’y refusa opiniâtrement ; il voulait, disait-il, consulter son fils, comme si, en province, un père riche consultait un fils qui n’a rien, autrement que pour la forme.</span></p>'),
 (400,17,1,'étape','<h1>2</h1><p><img src="data:image/jpeg;base64,"></p>'),
 (401,17,2,'étape','<h1>1</h1>'),
 (427,18,1,'étape','<p>Mettre les courgettes dans ton cul et <strong>attendre que ça fonde, pareil pour les </strong><strong style="background-color: rgb(255, 255, 255); color: rgb(240, 102, 102);">œufs</strong><strong>.</strong></p>'),
 (428,18,2,'astuce','<h3>L''œuf est issu du <strong>fion </strong>de la poule.</h3><p><img src="uploads/img_69ebe9b578718.jpg"></p><p>Ma femme a réellement beaucoup de tête ! se disait, le lendemain à six heures du matin, le maire de <u>Verrières</u>, en descendant à la scie du <strong><em>père Sorel</em></strong>. Quoi que je lui aie dit, pour conserver la supériorité qui m’appartient, je n’avais pas songé que si je ne prends pas ce petit abbé Sorel, qui, dit-on, sait le latin comme un ange, le directeur du dépôt, cette âme sans repos, pourrait bien avoir la même idée que moi et me l’enlever. Avec quel ton de suffisance il parlerait du <strong>précepteur de ses enfants</strong> !... Ce précepteur, une fois à moi, portera-t-il la soutane ?</p>');
